-- TORTILLA MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'TORTILLA MUDAH',
  'tortilla-mudah',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/tortilla-mudah.jpeg',
  NULL,
  '[{"name":"tepung gandum","amount":"350","unit":"g","isSection":false},{"name":"air panas (dihihkan air seketika- ketepikan 2 minit baru guna)","amount":"200","unit":"g","isSection":false},{"name":"garam (rata, tidak bertimbun)","amount":"1","unit":"sudu kecil","isSection":false},{"name":"minyak sayuran","amount":"2","unit":"sudu besar","isSection":false}]'::jsonb,
  '["Uli doh: Masukkan tepung, garam, minyak sayuran dan air panas. Gaul dengan sudu dahulu (supaya tak panas) Bila doh dah suam sikit, uli dengan tangan sampai licin dan lembut. Anggaran 3minit.","Rehatkan doh: Masukkan doh dalam plastik atau tutup rapat. Rehatkan selama 20 minit supaya gluten relaks dan senang untuk canai.","Bentukkan doh: Uli seketika. Bahagikan doh kepada 10-12 bahagian sama besar. Canaikan setiap bahagian setipis mungkin.","Masak: Panaskan kuali tanpa minyak. Masak setiap tortilla selama 30-60 saat setiap sisi sehingga ada tompok coklat.","Lembutkan tortilla: Selepas masak, renjis sedikit air pada setiap keping. Susun bertindih dan tutup dengan cling film / kertas minyak / aluminium foil. Rehatkan 10-20 minit supaya lembut, lentur dan tak pecah."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- BEEF DONER KEBAB
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'BEEF DONER KEBAB',
  'beef-doner-kebab',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/beef-doner-kebab.jpeg',
  NULL,
  '[{"name":"daging lembu/lamb cincang","amount":"1","unit":"kg","isSection":false},{"name":"bawang besar parut (perah sedikit air kalau terlalu banyak jus)","amount":"2","unit":"biji","isSection":false},{"name":"yogurt","amount":"¼","unit":"cawan","isSection":false},{"name":"bawang putih parut","amount":"1","unit":"sudu besar","isSection":false},{"name":"paprika","amount":"1","unit":"sudu besar","isSection":false},{"name":"serbuk jintan putih (cumin)","amount":"1","unit":"sudu besar","isSection":false},{"name":"parsley kering","amount":"1","unit":"sudu besar","isSection":false},{"name":"garam","amount":"1","unit":"sudu kecil","isSection":false},{"name":"lada hitam","amount":"1","unit":"sudu kecil","isSection":false},{"name":"serbuk kayu manis","amount":"½","unit":"sudu kecil","isSection":false},{"name":"halia serbuk (atau parut)","amount":"½","unit":"sudu kecil","isSection":false},{"name":"buah pelaga serbuk (jika ada)","amount":"½","unit":"sudu kecil","isSection":false},{"name":"bunga cengkih serbuk (jika ada)","amount":"½","unit":"sudu kecil","isSection":false}]'::jsonb,
  '["Panaskan oven pada suhu 250°C (450°F).","Dalam mangkuk besar, satukan daging cincang, bawang parut, yogurt, bawang putih, dan semua rempah.","Gaul hingga semuanya sebati dan adunan menjadi melekit.","Bentangkan baking paper, ratakan adunan daging di atasnya dan gulung ketat dan kemas.","Letakkan roll dalam bekas pembakar dan bakar dalam oven yang telah dipanaskan pada 250°C (450°F) selama 15 minit.","Keluarkan, toskan lebihan jus, buka baking paper, dan pindahkan daging ke atas tray.","Broil/grill selama ±5 minit atau sehingga permukaan perang dan sedikit crispy.","Sapu dengan butter cair, kemudian hiris nipis."]'::jsonb,
  NULL,
  '["Main","Beef"]'::jsonb,
  false
);

