-- SANDWICH CHOCOLATE CAKE
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SANDWICH CHOCOLATE CAKE',
  'sandwich-chocolate-cake',
  'Dessert',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/sandwich-chocolate-cake.jpeg',
  NULL,
  '[{"name":"Bahan A – Adunan Kuning","amount":"","unit":"","isSection":true},{"name":"tepung low-gluten (½ cup / 0.4 cup)","amount":"60","unit":"g","isSection":false},{"name":"serbuk koko (1 sudu besar)","amount":"10","unit":"g","isSection":false},{"name":"minyak sayuran/masak (4 sudu besar)","amount":"60","unit":"g","isSection":false},{"name":"air (4 sudu besar)","amount":"60","unit":"g","isSection":false},{"name":"kuning telur (Gred A/B)","amount":"5","unit":"","isSection":false},{"name":"Bahan B – Meringue","amount":"","unit":"","isSection":false},{"name":"putih telur (Gred A/B)","amount":"5","unit":"","isSection":false},{"name":"jus lemon (5g) / ¼ tsp cream of tartar/ ½ tsp cuka putih","amount":"1","unit":"tsp","isSection":false},{"name":"gula (3 sudu besar)","amount":"40","unit":"g","isSection":false},{"name":"Bahan C – Filling","amount":"","unit":"","isSection":true},{"name":"whipping cream (½ cup), pukul hingga kental","amount":"120","unit":"g","isSection":false},{"name":"gula (1 sudu besar)","amount":"10","unit":"g","isSection":false}]'::jsonb,
  '["Bahagian 1: Sediakan Adunan Kuning","Dalam bekas, masukkan tepung, serbuk koko dan minyak, kacau hingga sebati.","Kemudian masukkan air. Kacau sehingga sebati.","Masukkan kuning telur, kacau sebati dan smooth. Ketepikan.","── Bahagian 2: Sediakan Adunan Meringue ──","Dalam mangkuk bersih, pukul putih telur dan lemon juice sampai berbuih.","Masukkan gula sedikit demi sedikit.","Pukul sehingga soft peak – almost stiff peak (bentuk puncak lembut tetapi stabil).","Bahagian 3: Satukan Adunan","Ambil 1/3 meringue, gaul dalam adunan kuning.","Masuka semua adunan kuning tadi ke dalam baki meringue. Lipat (folding) dengan perlahan supaya tidak pecah udara. Guna spatula.","Pastikan adunan ringan dan fluffy.","Bahagian 4: Bakar Kek","Panaskan oven pada suhu 150°C – 160°C selama 15minit. Off kipas. Api atas bawah.","Tuang ke dalam loyang square 10-11 inch atau loyang nipis “sheet”.","Hentak sedikit loyang untuk keluarkan bubble besar.","Bakar 150°C – 160°C selama 25-30 minit (bergantung oven).","Bila masak, terbalikkan atas rak dan biarkan sejuk.","Bahagian 5: Assembly Sandwich Cake","Potong bahagian tepi-tepi kek untuk hasil yang kemas.","Kemudian, belah kek kepada 2 bahagian.","Pukul whipping cream fluffy. Sapu krim nipis & rata di tengah 1 bahagian kek.","Tutup dengan 1 lagi kek untuk lapisan atas.","Potong bentuk sandwich (segi empat / panjang).","Simpan dalam peti 1-2 jam sebelum makan—lagi sedap."]'::jsonb,
  '["Tips Supaya Kek Extra Soft & Moist:\n1. Jangan overmix—adunan kena ringan.\n2. Pakai suhu rendah supaya kek tak naik cepat & runtuh.\n3. Kalau nak lagi moist, boleh spray sedikit air gula pada kek sebelum letak cream."]',
  '["Dessert"]'::jsonb,
  false
);

-- AYAM BAWANG CWC
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'AYAM BAWANG CWC',
  'ayam-bawang-cwc',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/ayam-bawang-cwc.jpeg',
  NULL,
  '[{"name":"Bahan Kisar Halus","amount":"","unit":"","isSection":true},{"name":"bawang putih","amount":"3","unit":"ulas","isSection":false},{"name":"halia","amount":"1","unit":"inci","isSection":false},{"name":"bawang besar","amount":"1","unit":"biji","isSection":false},{"name":"Bahan Rempah 4 Sekawan:","amount":"","unit":"","isSection":false},{"name":"kayu manis","amount":"1","unit":"batang","isSection":false},{"name":"kuntum bunga lawang","amount":"2","unit":"","isSection":false},{"name":"buah pelaga","amount":"3","unit":"biji","isSection":false},{"name":"kuntum bunga cengkih","amount":"4","unit":"","isSection":false},{"name":"Bahan Lain","amount":"","unit":"","isSection":true},{"name":"1/2 cawan minyak masak","amount":"1","unit":"","isSection":false},{"name":"/2 ekor ayam","amount":"1","unit":"","isSection":false},{"name":"garam","amount":"1","unit":"sudu kecil","isSection":false},{"name":"serbuk kunyit","amount":"1","unit":"sudu kecil","isSection":false},{"name":"daun pandan","amount":"1","unit":"helai","isSection":false},{"name":"daun kari","amount":"1","unit":"tangkai","isSection":false},{"name":"1/2 sudu besar serbuk cili","amount":"1","unit":"","isSection":false},{"name":"serbuk kari daging/ayam","amount":"1","unit":"sudu besar","isSection":false},{"name":"/2 sudu kecil serbuk jintan manis","amount":"1","unit":"","isSection":false},{"name":"serbuk jintan putih","amount":"1","unit":"sudu kecil","isSection":false},{"name":"/2 sudu kecil serbuk garam masala","amount":"1","unit":"","isSection":false},{"name":"sos cili","amount":"2","unit":"sudu besar","isSection":false},{"name":"sos tiram","amount":"1","unit":"sudu besar","isSection":false},{"name":"sos tomato","amount":"2","unit":"sudu besar","isSection":false},{"name":"Air","amount":"secukupnya","unit":"","isSection":false},{"name":"Garam","amount":"secukup rasa","unit":"","isSection":false},{"name":"Bahan Bawang Goreng","amount":"","unit":"","isSection":true},{"name":"bawang besar (dihiris & digoreng sehingga kekuningan)","amount":"2","unit":"biji","isSection":false}]'::jsonb,
  '["Goreng bawang 2 biji tadi sehingga kekuningan.","Gaulkan ayam dengan garam dan kunyit.","Perap sekejap kemudian goreng sehingga 70% masak. Angkat dan ketepikan.","Panaskan minyak, tumis rempah 4 sekawan, daun kari dan daun pandan sehingga wangi.","Masukkan bahan kisar halus dan tumis sehingga pecah minyak.","Masukkan serbuk cili, serbuk kari daging, jintan manis, jintan putih dan garam masala. Tumis hingga naik bau.","Tambah sos cili, sos tiram, dan sos tomato. Gaul rata.","Masukkan ayam yang telah digoreng tadi. Tambah sedikit air tapisan bahan kisar jika perlu. Tutup periuk seketika. Masak selama 10minit.","Masak sehingga kuah pekat dan ayam sebati dengan rempah.","Akhir sekali, masukkan bawang goreng. Gaul rata dan siap untuk dihidang!"]'::jsonb,
  NULL,
  '["Main","Ayam"]'::jsonb,
  false
);

-- NASI PANDAN SIMPLE
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'NASI PANDAN SIMPLE',
  'nasi-pandan-simple',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/nasi-pandan-simple.jpeg',
  NULL,
  '[{"name":"beras basmati (boleh rendam 15min jika suka)","amount":"2","unit":"cawan","isSection":false},{"name":"air","amount":"3","unit":"cawan","isSection":false},{"name":"daun pandan (siat dan disimpul)","amount":"2","unit":"helai","isSection":false},{"name":"garam","amount":"1","unit":"sudu kecil","isSection":false},{"name":"butter atau margarine","amount":"2","unit":"sudu kecil","isSection":false},{"name":"Bahan Tumis","amount":"","unit":"","isSection":true},{"name":"bawang putih (ketuk)","amount":"1","unit":"ulas","isSection":false},{"name":"bawang merah hiris (optional)","amount":"1","unit":"","isSection":false},{"name":"bunga lawang","amount":"1","unit":"biji","isSection":false}]'::jsonb,
  '["Panaskan 1 sudu besar butter / minyak.","Tumiskan bahan tumis sehingga naik bau dan beraroma.","Bila dah naik bau, masukkan 2 helai daun pandan simpul.","Masukkan beras (2 cawan) dan goreng sekejap dalam tumisan (3 minit).","Pindahkan beras ke rice cooker atau terus masak dalam periuk/kuali.","Masukkan air ikut sukatan, tambah 1 sudu kecil garam + ½ sudu kecil butter.","Masak nasi macam biasa. Siap."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- KATSU CURRY
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'KATSU CURRY',
  'katsu-curry',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/katsu-curry.jpeg',
  NULL,
  '[{"name":"bawang holland (hiris)","amount":"3","unit":"biji","isSection":false},{"name":"lobak merah (potong kiub)","amount":"1","unit":"","isSection":false},{"name":"halia (hiris)","amount":"30","unit":"g","isSection":false},{"name":"bawang putih (hiris)","amount":"5","unit":"ulas","isSection":false},{"name":"minyak","amount":"5","unit":"sudu besar","isSection":false},{"name":"epal manis (parut/ potong kiub)","amount":"1","unit":"","isSection":false},{"name":"bunga lawang (star anise)","amount":"2","unit":"","isSection":false},{"name":"kayu manis","amount":"1","unit":"batang","isSection":false},{"name":"serbuk kari","amount":"2","unit":"sudu besar","isSection":false},{"name":"garam masala","amount":"1","unit":"sudu kecil","isSection":false},{"name":"kunyit","amount":"2","unit":"sudu kecil","isSection":false},{"name":"lada hitam","amount":"1","unit":"sudu kecil","isSection":false},{"name":"garam","amount":"2","unit":"sudu kecil","isSection":false},{"name":"serbuk cili","amount":"1","unit":"sudu kecil","isSection":false},{"name":"butter","amount":"100","unit":"g","isSection":false},{"name":"tepung gandum","amount":"75","unit":"g","isSection":false},{"name":"kicap","amount":"1","unit":"sudu besar","isSection":false},{"name":"stok ayam (2 kiub ayam larut dengan air panas)","amount":"900","unit":"ml","isSection":false},{"name":"MSG","amount":"1","unit":"sudu kecil","isSection":false},{"name":"madu","amount":"1-2","unit":"sudu besar","isSection":false}]'::jsonb,
  '["Hiris kasar bawang, lobak merah, epal, halia dan bawang putih.","Panaskan 5 sudu besar minyak dalam periuk.","Tumis bawang hingga layu dan sedikit perang.","Masukkan lobak merah, bawang putih, halia dan epal. Tumis 3-4 minit.","Masukkan rempah. Masukkan star anise dan cinnamon stick.","Tambah serbuk kari, garam masala, kunyit, lada hitam dan serbuk cili.","Gaul hingga rempah naik bau (1 minit).","Keluarkan bunga lawang dan kayu manis. Kemudian buat roux (untuk pekatkan curry) Masukkan 100g butter dan biar cair sepenuhnya.","Masukkan 75g tepung gandum, kacau sampai jadi pes pekat dan warna keemasan.","Masak kuah, tuang 900ml stok ayam sedikit demi sedikit sambil kacau supaya tidak berketul.","Masukkan 1 sudu besar kicap, 1 sudu kecil MSG dan 1-2 sudu besar madu.","Renez 20-25 minit sehingga semua sayur lembut. Tutup api. Sejukkan seketika.","Kisar kuah hingga halus atau biar berketul halus ikut selera.","Tapis dan masukkan semula ke dalam periuk dan renez 5 minit.","Sesuaikan rasa — tambah garam, madu atau kicap jika perlu."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- CHICKEN KATSU
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'CHICKEN KATSU',
  'chicken-katsu',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/chicken-katsu.jpeg',
  NULL,
  '[{"name":"dada ayam besar","amount":"2-3","unit":"","isSection":false},{"name":"Garam dan lada hitam","amount":"secukupnya","unit":"","isSection":false},{"name":"Tepung gandum","amount":"secukupnya","unit":"","isSection":false},{"name":"telur","amount":"3","unit":"biji","isSection":false},{"name":"air","amount":"2","unit":"sudu besar","isSection":false},{"name":"serbuk roti panko (serbuk roti warna putih)","amount":"200","unit":"g","isSection":false},{"name":"Minyak untuk menggoreng","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Belah dada ayam secara butterfly kalau tebal, kemudian ratakan (ketuk) sedikit dengan rolling pin / belakang periuk.","Perasakan dengan garam dan lada hitam.","── 3. Sediakan 3 mangkuk ──","• Mangkuk 1: Tepung gandum","• Mangkuk 2: 3 biji telur + 2 sudu air (pukul sebati)","• Mangkuk 3: Panko breadcrumbs","Salut ayam dengan tepung → celup telur → salut panko hingga penuh.","Panaskan minyak (shallow fry). Medium heat. Api sederhana.","Goreng ayam 3-4 minit setiap sisi sehingga keemasan dan rangup.","Toskan ayam di atas cooling rack. Siap"]'::jsonb,
  NULL,
  '["Main","Ayam"]'::jsonb,
  false
);

-- SPECIAL KATSU RICE
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SPECIAL KATSU RICE',
  'special-katsu-rice',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/special-katsu-rice.jpeg',
  NULL,
  '[{"name":"(500g) beras basmati","amount":"2","unit":"cawan","isSection":false},{"name":"(800ml) air","amount":"3","unit":"cawan","isSection":false},{"name":"garam","amount":"2","unit":"sudu kecil","isSection":false},{"name":"kayu manis","amount":"1","unit":"batang","isSection":false},{"name":"cengkih","amount":"5","unit":"","isSection":false},{"name":"minyak","amount":"2","unit":"sudu besar","isSection":false},{"name":"kitchen towel/ kain bersih","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Cuci bersih dan rendamkan beras selama 30minit. Toskan.","Dalam periuk, set api medium heat. Didihkan air,","Kemudian masukkan garam kayu manis, cengkih, garam dan minyak.","Seterusnya masukkan beras. Biarkan nasi masak seketika. Perhatikan bila bila permukaan air atas nasi semakin berkurang. Tanpa tutup periuk.","Ambil kitchen towel dan ikat (tutup) pada permukaan tudung periuk. Seterusnya set api perlahan dan tutup periuk. Proses ini seperti buat steam rice.","Sambung masak anggaran 15minit. Air akan kering sepenuhnya. Siap."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

