-- KUEY TEOW GORENG KERANG MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'KUEY TEOW GORENG KERANG MUDAH',
  'kuey-teow-goreng-kerang-mudah',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/kuey-teow-goreng-kerang-mudah.jpeg',
  NULL,
  '[{"name":"pek kuetiau (400gm)","amount":"1","unit":"","isSection":false},{"name":"minyak masak","amount":"1½","unit":"sudu besar","isSection":false},{"name":"bawang putih (cincang)","amount":"1–2","unit":"ulas","isSection":false},{"name":"cili kisar","amount":"1","unit":"sudu besar","isSection":false},{"name":"sos tiram","amount":"1","unit":"sudu besar","isSection":false},{"name":"mangkuk kerang rebus","amount":"¼","unit":"","isSection":false},{"name":"air rebusan kerang","amount":"2","unit":"sudu besar","isSection":false},{"name":"Tambah sedikit lagi air rebusan kerang jika nak basah","amount":"","unit":"","isSection":false},{"name":"kicap cair","amount":"2","unit":"sudu besar","isSection":false},{"name":"sos pekat karamel","amount":"1","unit":"sudu besar","isSection":false},{"name":"kicap manis","amount":"2","unit":"sudu besar","isSection":false},{"name":"taugeh","amount":"Segenggam","unit":"","isSection":false},{"name":"telur","amount":"1–2","unit":"biji","isSection":false},{"name":"minyak (untuk telur)","amount":"Sedikit","unit":"","isSection":false},{"name":"serbuk lada sulah","amount":"¼","unit":"sudu kecil","isSection":false},{"name":"kucai","amount":"Segenggam","unit":"","isSection":false},{"name":"Garam","amount":"secukup rasa","unit":"","isSection":false}]'::jsonb,
  '["── Cara rebus kerang (ada kulit) ──","Basuh kerang, rendam 15 minit dalam air garam supaya keluar pasir.","Dalam periuk, didihkan air tanpa garam.","Bila air dah mendidih betul-betul, masukkan kerang.","Rebus 1½ – 2 minit sahaja, atau sehingga cengkerang mula terbuka.","Angkat terus, tos dan rendam dalam air sejuk/ais untuk hentikan proses masak","Kopek dan simpan air kerang (tapis dulu) untuk digunakan dalam kuetiau.","── Cara rebus isi kerang (tanpa kulit) ──","Didihkan air dalam periuk.","Bila air betul-betul mendidih, tutup api dulu.","Masukkan isi kerang ke dalam air panas tersebut.","Biarkan 30–45 saat sahaja.","Toskan dan terus guna untuk masakan.","* Teknik ini panaskan kerang tanpa overcook—jadi tetap lembut.","── Cara Goreng Kuehtiau ──","Panaskan minyak. Tumis bawang putih hingga wangi.","Masukkan cili kisar, tumis sampai pecah minyak.","Tambah sos tiram dan sedikit air rebusan kerang. Masukkan kuetiau, gaul","rata.","Masukkan kicap cair, sos pekat karamel dan kicap manis. Gaul sampai","warna sekata.","Ketepikan kuehtiau ketepi kuali, Letakkan sedikit minyak dan pecahkan","telur. Perasakan dengan lada sulah & garam sedikit.","Biarkan telur keras sedikit baru kacau hancurkan.","Kemudian, masukkan kerang rebus, taugeh dan daun kucai. Rasa dan","suaikan dengan citarasa.","Tambah sedikit air rebusan kerang kalau nak lembap.Siap!"]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- CHICKEN SANDWICH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'CHICKEN SANDWICH',
  'chicken-sandwich',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/chicken-sandwich.jpeg',
  NULL,
  '[{"name":"Bahan Ayam","amount":"","unit":"","isSection":true},{"name":"dada ayam / thigh","amount":"1","unit":"keping","isSection":false},{"name":"garam","amount":"1","unit":"tsp","isSection":false},{"name":"/2 tsp black pepper","amount":"1","unit":"","isSection":false},{"name":"/2 tsp paprika","amount":"1","unit":"","isSection":false},{"name":"/2 tsp bawang putih serbuk","amount":"1","unit":"","isSection":false},{"name":"minyak","amount":"1-2","unit":"tsp","isSection":false},{"name":"Bahan Sos","amount":"","unit":"","isSection":true},{"name":"mayo","amount":"4","unit":"tbsp","isSection":false},{"name":"ketchup","amount":"2","unit":"tbsp","isSection":false},{"name":"mustard sauce","amount":"1","unit":"tbsp","isSection":false},{"name":"hot sauce (Tabasco / Frank''s)","amount":"1","unit":"tbsp","isSection":false},{"name":"madu","amount":"1","unit":"tsp","isSection":false},{"name":"lemon juice","amount":"1","unit":"tsp","isSection":false},{"name":"garlic powder","amount":"1","unit":"tsp","isSection":false},{"name":"/4 tsp paprika (smoky)","amount":"1","unit":"","isSection":false},{"name":"Garam & black pepper","amount":"secukup rasa","unit":"","isSection":false},{"name":"Bahan lain","amount":"","unit":"","isSection":true},{"name":"Roti pilihan","amount":"","unit":"","isSection":false},{"name":"Cheese","amount":"","unit":"","isSection":false},{"name":"Salad","amount":"","unit":"","isSection":false}]'::jsonb,
  '["── Cara sediakan sos ──","Masukkan semua bahan dalam mangkuk.","Kacau hingga sebati & smooth.","Rasa, adjust garam/pepper atau lemon jika perlu.","Simpan dalam peti sejuk sementara siapkan ayam & roti.","── Cara sediakan ayam ──","Ratakan ayam. Kemudian boleh buat Dry Brine. Letakkan sedikit garam. Masukkan dalam peti (chiller), biar terbuka 30minit - 12 jam. Tak perlu tutup ayam. Biar terdedah sahaja.","Dry rub ayam dengan garam + semua serbuk. Kemudian, Lumur 1-2 tsp minyak pada permukaan ayam.","Panaskan airfryer 3minit. Suhu 160°C","Bakar","• 160°C 10-12 minit, terbalikkan","• 160°C 8-10 minit lagi","• Nak garing: tambah 200°C 2-3 minit.","Rehatkan ayam 5-10 minit sebelum potong supaya jus kekal.","── Cara buat sandwich ──","Toast roti: sapu mentega → pan atau airfryer 2-3 minit.","Sapu sos pada kedua-dua belah roti.","Letak salad → tomato → ayam hiris → keju.","Tutup roti, tekan sikit bagi padat.","Potong dua supaya nampak layer lawa."]'::jsonb,
  NULL,
  '["Main","Ayam"]'::jsonb,
  false
);

-- IKAN JAKET MASAK LEMAK CILI PADI BERSAMA REBUNG
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'IKAN JAKET MASAK LEMAK CILI PADI BERSAMA REBUNG',
  'ikan-jaket-masak-lemak-cili-padi-bersama-rebung',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/ikan-jaket-masak-lemak-cili-padi-bersama-rebung.jpeg',
  NULL,
  '[{"name":"Bahan kisar","amount":"","unit":"","isSection":true},{"name":"cili padi merah dan hijau (boleh lebihkan jika suka)","amount":"10-15","unit":"","isSection":false},{"name":"biji bawang besar","amount":"1","unit":"biji","isSection":false},{"name":"kunyit hidup","amount":"2","unit":"inci","isSection":false},{"name":"air (250ml)","amount":"1","unit":"Cawan","isSection":false},{"name":"Bahan Lain","amount":"","unit":"","isSection":true},{"name":"ikan cencaru/kembung/mabung etc (di bakar seketika)","amount":"5","unit":"ekor","isSection":false},{"name":"rebung","amount":"500","unit":"gm","isSection":false},{"name":"kotak santan kecil (ikut citarasa boleh lebihkan)","amount":"2","unit":"","isSection":false},{"name":"asam gelugor (boleh tambah)","amount":"2-4","unit":"keping","isSection":false},{"name":"Air","amount":"secukupnya","unit":"","isSection":false},{"name":"Garam dan gula","amount":"secukup rasa","unit":"","isSection":false}]'::jsonb,
  '["── Cara ──","Kisar semua bahan sehingga halus. Ketepikan seketika.","Cara sediakan ikan (dibakar/panggang)","Bakar ikan yang telah dilumur dengan kunyit dan garam dalam kuali atau airfyer. Jika guna ikan cencaru, buang kulitnya.","Bakar atau panggang sehingga ikan sedikit pejal. Ketepikan seketika.","── Cara masak lauk ──","Dalam periuk, masukkan bahan kisar. Biarkan mendidih seketika.","Kemudian masukkan rebung dan tambahkan sedikit air jika perlu.","Renehkan semua bahan seketika sehingga rebung sedikit lembut.","Kemudian, masukkan santan cair atau air. Gaul sehingga semua bahan sebati.","Seterusnya, masukkan ikan yang telah di bakar/panggang awal tadi.","Kemudian masukkan santan pekat.","Biarkan lauk mendidih seketika kemudian, masukkan asam keping.","Boleh perasakan dengan garam dan gula jika perlu.","Rasa dan suaikan dengan citarasa.","Jika terlalu pedas boleh lebihkan santan dan seimbangkan rasa.","Sambung renehkan lauk seketika, kemudian tutup api dan boleh restingkan lauk. Siap."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- EASY FLAN (CRÈME CARAMEL)
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'EASY FLAN (CRÈME CARAMEL)',
  'easy-flan-crème-caramel',
  'Dessert',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/easy-flan-crème-caramel.jpeg',
  NULL,
  '[{"name":"Bahan Karamel","amount":"","unit":"","isSection":true},{"name":"gula","amount":"6","unit":"sudu besar","isSection":false},{"name":"/3 cawan air","amount":"1","unit":"","isSection":false},{"name":"Bahan Puding (Custard)","amount":"","unit":"","isSection":true},{"name":"telur (gred A/B)","amount":"4","unit":"biji","isSection":false},{"name":"gula pasir","amount":"½","unit":"cawan","isSection":false},{"name":"susu segar (500 ml)","amount":"2","unit":"cawan","isSection":false},{"name":"esen vanilla","amount":"1","unit":"sudu kecil","isSection":false},{"name":"garam","amount":"Secubit","unit":"","isSection":false},{"name":"ramekin (bekas yang bersesuaian)","amount":"4–6","unit":"","isSection":false}]'::jsonb,
  '["── Cara sediakan karamel ──","Tuangkan gula dan air. Kacau sehingga gula larut.","Panaskan sirap gula tersebut untuk membuat karamel dalam periuk sos (sauce pan) atas api sederhana perlahan.","Apabila ia mula berkaremel, jangan kacau — hanya goyangkan periuk dengan perlahan.","Jangan biarkan warna terlalu gelap kerana ia akan menjadi pahit. Bila warna sudah menjadi keemasan yang cantik, angkat dari api.","Tuangkan karamel yang telah siap ke dalam ramekin atau acuan pilihan anda.","Goyangkan acuan supaya dasar acuan disalut karamel secara rata.","Cara sediakan custard (puding)","Dalam mangkuk, kacau telur dan esen vanila sehingga sebati. Ketepikan.","Panaskan susu, gula dan garam. Api perlahan cukup sekadar naik asap sikit. Jangan sampai mendidih. Tutup api.","Tuang bancuhan susu panas perlahan-lahan ke dalam campuran telur sambil dikacau (untuk elak telur masak terlalu cepat).","Kemudian tapis custard ke dalam mangkuk lain untuk memastikan tekstur licin dan halus.","Cara Bakar Puding Karamel (Water Bath)","Tuang custard ke dalam ramekin yang telah di isi dengan karamel (gula hangus) yang telah dibuat awal tadi. Tuang perlahan-lahan. Boleh tapis juga kalau suka.","Letakkan ramekin dalam dulang pembakar dan tuang air panas sehingga menutupi separuh tinggi ramekin (kaedah water bath).","Bakar dalam Pre heated oven 140°C-160°C rak tengah, selama 30-50minit, sehingga custard set tetapi bahagian tengah masih sedikit bergoyang. Bergantung saiz ramekin, masa dan suhu juga akan berbeza.","Keluarkan ramekin dan biarkan sejuk sepenuhnya. Tutup permukaan creme caramel dengan cling wrap.","Simpan dalam peti ais sekurang-kurangnya 3-4 jam atau semalaman.","── Jika nak kukus (Water bath) ──","Panaskan kukusan. Tuang custard ke dalam ramekin yang telah berisi gula hangus.","Tutup permukaan ramekin dengan aluminium foil untuk elak wap menitik ke atas custard.","Letakkan ramekin dalam dulang berisi air. Kemudian masuk dalam pengukus.","Kukus dengan api sederhana-rendah selama 35-45 minit sehingga custard set tetapi masih sedikit bergoyang di tengah.","Keluarkan ramekin, biarkan sejuk, kemudian simpan dalam peti ais 3-4 jam atau semalaman."]'::jsonb,
  '["Nota tambahan:\n1. Saiz bekas / loyang\n• Panjang: 9 inci\n• Lebar: 12 inci\n• Tinggi: 2 inci\n2. Alternatif lain jika tiada:\n• Loyang bulat: 9–10 inci diameter, tinggi 2 inci\n• Loyang segiempat / kotak: 9 × 12 inci, tinggi 2 inci\n3. Pastikan loyang cukup dalam untuk water bath, supaya bahagian tengah tidak cepat kering."]',
  '["Dessert"]'::jsonb,
  false
);

-- CHICKEN ALFREDO MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'CHICKEN ALFREDO MUDAH',
  'chicken-alfredo-mudah',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/chicken-alfredo-mudah.jpeg',
  NULL,
  '[{"name":"pek Pasta fettuccine","amount":"1","unit":"","isSection":false},{"name":"dada ayam tanpa tulang dan kulit (belah dua jika tebal)","amount":"450","unit":"g","isSection":false},{"name":"garam","amount":"¾","unit":"sudu kecil","isSection":false},{"name":"lada hitam","amount":"¼","unit":"sudu kecil","isSection":false},{"name":"minyak zaitun / minyak masak biasa","amount":"2","unit":"sudu besar","isSection":false},{"name":"mentega","amount":"1","unit":"sudu besar","isSection":false},{"name":"Bahan Sos Alfredo","amount":"","unit":"","isSection":false},{"name":"krim masak / susu penuh krim + sedikit tepung jagung (alternatif untuk heavy cream)","amount":"2","unit":"cawan","isSection":false},{"name":"mentega (113 g)","amount":"½","unit":"cawan","isSection":false},{"name":"bawang putih, cincang halus (2 sudu besar)","amount":"6","unit":"ulas","isSection":false},{"name":"garam","amount":"½","unit":"sudu kecil","isSection":false},{"name":"lada hitam","amount":"½","unit":"sudu kecil","isSection":false},{"name":"keju cheddar / keju mozarella / keju tempatan yang masin (alternatif untuk Parmesan)","amount":"1","unit":"cawan","isSection":false},{"name":"Hiasan","amount":"","unit":"","isSection":false},{"name":"Daun parsley segar, dicincang","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Rebus Pasta","• Didihkan periuk besar berisi air masin di atas api sederhana tinggi.","• Sementara menunggu air mendidih, perasakan ayam dengan garam dan lada hitam.","Masak Ayam","• Panaskan minyak dan mentega dalam kuali besar atas api sederhana tinggi.","• Masukkan ayam, masak hingga keemasan di kedua-dua belah, lebih kurang 7–9 minit setiap sisi (atau sehingga suhu dalaman ayam mencecah 74°C / 165°F).","• Keluarkan ayam dari kuali, tutup untuk mengekalkan panas. Lap kuali untuk bersihkan.","Masak Fettuccine","• Masukkan pasta ke dalam air yang sedang mendidih, masak ikut arahan pada bungkusan hingga al dente.","• Toskan pasta, simpan ½ cawan air rebusan untuk digunakan kemudian. Pastikan pasta tetap hangat.","Buat Sos Alfredo","• Dalam kuali yang sama, masukkan krim, mentega, dan bawang putih.","• Masak di atas api sederhana, kacau selalu hingga mentega cair.","• Masukkan garam dan lada hitam. Biarkan sos mendidih perlahan.","• Kacau sos sentiasa hingga sedikit pekat, lebih kurang 5 minit. Pastikan api tidak terlalu tinggi supaya sos tidak mendidih kuat.","Masukkan Keju","• Masukkan Parmesan (atau alternatif keju yang sesuai) sedikit demi sedikit, kacau hingga sos licin.","• Angkat dari api.","Gabungkan Pasta","• Masukkan pasta yang telah dimasak ke dalam sos, gaul rata.","• Tambah sedikit air rebusan pasta jika sos terlalu pekat.","Hidangkan Ayam & Pasta","• Hiriskan ayam setebal 1.25 cm (½ inci).","• Bahagikan pasta ke dalam pinggan, letakkan ayam di atas.","• Hiaskan dengan daun parsley cincang. Hidangkan segera."]'::jsonb,
  NULL,
  '["Main","Ayam"]'::jsonb,
  false
);

-- SARDIN TUMIS ALA THAI
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SARDIN TUMIS ALA THAI',
  'sardin-tumis-ala-thai',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/sardin-tumis-ala-thai.jpeg',
  NULL,
  '[{"name":"besar ikan sardin (ambil kuah sekali)","amount":"1","unit":"tin","isSection":false},{"name":"bawang merah – hiris","amount":"2","unit":"biji","isSection":false},{"name":"bawang putih – cincang/ketuk","amount":"3","unit":"ulas","isSection":false},{"name":"cili kisar","amount":"2","unit":"sudu makan","isSection":false},{"name":"kicap manis","amount":"Sedikit","unit":"","isSection":false},{"name":"daun limau purut – koyak dua","amount":"4","unit":"helai","isSection":false},{"name":"Cili hijau/merah – belah dua","amount":"","unit":"","isSection":false},{"name":"tomato – potong wedges","amount":"1","unit":"biji","isSection":false},{"name":"Garam & gula","amount":"secukup rasa","unit":"","isSection":false},{"name":"Jus limau (1","amount":"2","unit":"sudu makan","isSection":false}]'::jsonb,
  '["Sediakan ikan sardin. Keluarkan ikan sardin dari tin perlahan-lahan supaya tak pecah. Lap/lalukan air dan keringkan ikan sardin supaya tidak meletup semasa di goreng.","Simpan kuah sos tomato tepi (kita guna kemudian).","Goreng ikan sardin. Panaskan sedikit minyak. Goreng ikan sardin sekejap saja, lebih kurang 1–2 minit setiap sisi.","Cukup sampai luar dia crispy sikit – jangan terlalu lama nanti keras. Angkat dan ketepikan.","Tumis bawang merah & bawang putih sampai wangi.","Masukkan cili kisar dan tumis sampai pecah minyak.","Tambahkan kicap manis, garam, gula. Masak sekejap.","Masukkan kuah sardin yang kita simpan tadi. Gaul sebati.","Masukkan daun limau purut dan lada hijau. Reneh bagi aroma naik. Masukkan tomato.","Akhir sekali masukkan ikan sardin yang digoreng. Jangan kacau kuat.","Tutup api dan perahkan jus limau. Siap."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- LEMAK SOHUN & FUCUK MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'LEMAK SOHUN & FUCUK MUDAH',
  'lemak-sohun-fucuk-mudah',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/lemak-sohun-fucuk-mudah.jpeg',
  NULL,
  '[{"name":"sohun – rendam lembut","amount":"1","unit":"genggam","isSection":false},{"name":"fucuk – rendam lembut","amount":"1","unit":"cawan","isSection":false},{"name":"bawang merah – hiris","amount":"1","unit":"biji","isSection":false},{"name":"bawang putih – hiris","amount":"2","unit":"ulas","isSection":false},{"name":"ikan bilis tumbuk","amount":"2","unit":"sudu makan","isSection":false},{"name":"santan (1 kotak santan kecil)","amount":"1","unit":"cawan","isSection":false},{"name":"Garam & gula","amount":"secukupnya","unit":"","isSection":false},{"name":"Air","amount":"secukupnya","unit":"","isSection":false},{"name":"Cili padi (optional)","amount":"","unit":"","isSection":false},{"name":"Lada hitam sikit (optional)","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Rendam sohun dan fucuk seketika - sehingga lembut sedikit.","Panaskan sedikit minyak. Tumis bawang merah & bawang putih hingga wangi.","Masukkan ikan bilis tumbuk dan tumis sampai naik bau — ini yang buat kuah jadi sedap.","Tuang air ikut banyak kuah yang nak. Masukkan fucuk. Reneh seketika 3 minit. Jika tak rendam awal lebihkan lagi masa mereneh.","Tuang santan, kacau perlahan. Biarkan hampir mendidih (jangan biar bergolak kuat).","Bila kuah kuah elok panas, masukkan sohun. 1–2 minit saja.","Tambah garam & gula. Kalau nak pedas, masuk cili padi. Kalau nak wangi, letak sikit lada hitam. Rasa dan suaikan dengan citarasa.","Reneh sekejap. Jangan lama sangat supaya sohun tak putus. Siap."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- ROASTED CHICKEN ALA KR
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'ROASTED CHICKEN ALA KR',
  'roasted-chicken-ala-kr',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/roasted-chicken-ala-kr.jpeg',
  NULL,
  '[{"name":"Bahan Ayam","amount":"","unit":"","isSection":true},{"name":"ayam (1.4-1.8kg)","amount":"1","unit":"ekor","isSection":false},{"name":"lemon (perah jus & masukkan rinds ke dalam ayam)","amount":"1","unit":"","isSection":false},{"name":"labu bawang putih – potong dua melintang","amount":"1","unit":"","isSection":false},{"name":"bawang besar – hiris tebal","amount":"1","unit":"biji","isSection":false},{"name":"thyme (3 dalam ayam, 3 luar ayam)","amount":"6","unit":"tangkai","isSection":false},{"name":"Bahan Butter Marinade","amount":"","unit":"","isSection":false},{"name":"butter cair","amount":"2","unit":"sudu besar","isSection":false},{"name":"minyak zaitun","amount":"1","unit":"sudu besar","isSection":false},{"name":"garam","amount":"1½","unit":"sudu kecil","isSection":false},{"name":"lada hitam","amount":"½","unit":"sudu kecil","isSection":false},{"name":"madu / brown sugar","amount":"1","unit":"sudu besar","isSection":false},{"name":"jus lemon extra","amount":"2","unit":"sudu besar","isSection":false},{"name":"cuka epal (optional tapi sangat sedap)","amount":"½","unit":"sudu kecil","isSection":false},{"name":"garlic powder","amount":"1","unit":"sudu kecil","isSection":false},{"name":"onion powder","amount":"½","unit":"sudu kecil","isSection":false},{"name":"paprika","amount":"½","unit":"sudu kecil","isSection":false},{"name":"thyme kering / rosemary","amount":"½","unit":"sudu kecil","isSection":false},{"name":"cayenne / serbuk cili","amount":"¼","unit":"sudu kecil","isSection":false},{"name":"Bahan Sayur (Jika Suka)","amount":"","unit":"","isSection":false},{"name":"Kentang","amount":"secukupnya – potong wedges besar","unit":"","isSection":false},{"name":"Carrot – potong besar (optional)","amount":"","unit":"","isSection":false},{"name":"Bawang besar – belah 4","amount":"","unit":"","isSection":false},{"name":"Capsicum – potong tebal","amount":"","unit":"","isSection":false},{"name":"Brokoli – potong florets besar","amount":"","unit":"","isSection":false},{"name":"Bahan seasoning sayur","amount":"","unit":"","isSection":true},{"name":"minyak","amount":"1-2","unit":"sudu besar","isSection":false},{"name":"garam","amount":"½","unit":"sudu kecil","isSection":false},{"name":"lada hitam","amount":"½","unit":"sudu kecil","isSection":false},{"name":"garlic powder","amount":"1","unit":"sudu kecil","isSection":false},{"name":"paprika","amount":"½","unit":"sudu kecil","isSection":false},{"name":"Optional: rosemary / thyme","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Preheat oven: 450°F (230°C).","Gaul kentang, carrot, bawang besar dengan seasoning.","Lap ayam sampai kering. Longgarkan kulit dada & paha.","Sapu marinade bawah kulit + seluruh permukaan ayam. Perah lemon atas ayam.","Masukkan ke dalam cavity, Lemon yang diperah, bawang putih dan 3 tangkai thyme.","Susun bawang besar & thyme di sekitar ayam dalam loyang.","Ikat kaki ayam dan peha di kepak ke bawah badan ayam.","Susun bawang besar dan baki thyme di sekeliling ayam dalam loyang.","Masukkan ayam & sayur awal, turunkan suhu oven ke 425°F (218°C). Selepas ayam masuk dalam oven.","Bakar 1 jam – 1 jam 30 minit (bergantung size ayam) basting setiap 30 minit.","Pada 25-30 minit terakhir sebelum ayam masak, masukkan capsicum & brokoli supaya masih crisp.","Periksa ayam capai 165°F (74°C) di bahagian paling tebal. Atau bila di cucuk tiada air berwarna berah keluar.","Keluarkan ayam & rehatkan 15 minit sebelum potong."]'::jsonb,
  NULL,
  '["Main","Ayam"]'::jsonb,
  false
);

-- SPECIAL GRAVY (ROASTED CHICKEN)
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
