  NULL,
  '[{"name":"pan drippings (dari chicken roasted)","amount":"2-3","unit":"sudu besar","isSection":false},{"name":"butter","amount":"1","unit":"sudu besar","isSection":false},{"name":"tepung","amount":"1","unit":"sudu besar","isSection":false},{"name":"air / chicken stock","amount":"1","unit":"cawan","isSection":false},{"name":"kicap manis / madu","amount":"½","unit":"sudu kecil","isSection":false},{"name":"jus lemon","amount":"1","unit":"sudu kecil","isSection":false},{"name":"lada hitam","amount":"¼","unit":"sudu kecil","isSection":false},{"name":"Garam","amount":"secukupnya","unit":"","isSection":false},{"name":"Optional","amount":"1","unit":"sudu kecil","isSection":false}]'::jsonb,
  '["Cairkan butter kemudian masukkan tepung dan kacau sampai light golden.","Masukkan pan drippings → kacau sebati.","Tuang air / stock sedikit demi sedikit dan kacau sampai smooth & pekat.","Perasa: kicap manis/madu + jus lemon + lada hitam + garam. Suaikan dengan citarasa.","Masak 2-3 minit sampai glossy & thick."]'::jsonb,
