  NULL,
  '[{"name":"beras basmati","amount":"2","unit":"cawan","isSection":false},{"name":"air / chicken stock","amount":"3","unit":"cawan","isSection":false},{"name":"butter","amount":"2","unit":"sudu besar","isSection":false},{"name":"bawang putih – cincang","amount":"4-5","unit":"ulas","isSection":false},{"name":"bawang besar – cincang","amount":"½","unit":"biji","isSection":false},{"name":"garam","amount":"½","unit":"sudu kecil","isSection":false},{"name":"lada hitam","amount":"½","unit":"sudu kecil","isSection":false},{"name":"parsley kering","amount":"1","unit":"sudu kecil","isSection":false},{"name":"thyme kering","amount":"½","unit":"sudu kecil","isSection":false},{"name":"Optional","amount":"1","unit":"","isSection":false}]'::jsonb,
