-- CRISPY PURPLE SWEET POTATO FRIES
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'CRISPY PURPLE SWEET POTATO FRIES',
  'crispy-purple-sweet-potato-fries',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/crispy-purple-sweet-potato-fries.jpeg',
  NULL,
  '[{"name":"keledek (ungu)","amount":"2","unit":"Biji","isSection":false},{"name":"tepung gandum","amount":"2","unit":"tbsp","isSection":false},{"name":"tepung jagung","amount":"2","unit":"tbsp","isSection":false},{"name":"/4 tsp baking powder","amount":"1","unit":"","isSection":false},{"name":"/4 baking soda","amount":"1","unit":"","isSection":false},{"name":"air","amount":"1","unit":"tbsp","isSection":false},{"name":"white vinegar","amount":"1","unit":"tbsp","isSection":false}]'::jsonb,
  '["Cuci bersih keledek dan buang kulit. Kemudian potong keledek dengan saiz yang hampir sama.","Soak dulu: Rendam keledek ungu dalam air sejuk 20-30 minit sebelum digaul dengan tepung, untuk keluarkan sedikit kanji dan kurangkan kelembapan.","Dalam mangkuk lain, masukkan tepung gandum, tepung jagung, baking powder dan baking soda. Gaul rata.","Dalam Mangkuk lain, masukkan air dan white vinegar.","Ambil semula keledek yang telah di potong dan rendam. Toskan dan keringkan sepenuhnya.","Masukkan sedikit bancuhan tepung tadi. Kemudian masukkan sedikit bancuhan vineger. Gaul rata.","Ulang Langkah 6 sebanyak 2 kali. Gaul rata.","Panaskan minyak pada suhu 160c. Guna cara chopsticks untuk check suhu.","Goreng dalam api sederhana selama 4 minit. Balik kan sentiasa.","Angkat dan toskan. Letak kan di atas cooling rack seketika.","Boleh Goreng dua kali (optional): Goreng pertama pada 160°C, angkat dan sejukkan 1-2 minit, kemudian goreng sekali lagi pada 180°C untuk ekstra rangup.","Perasakan dengan spice or apa sahaja yang anda suka. Selamat mencuba."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- SAMBAL SOTONG BERSANTAN
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SAMBAL SOTONG BERSANTAN',
  'sambal-sotong-bersantan',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/sambal-sotong-bersantan.jpeg',
  NULL,
  '[{"name":"Bahan Kisar","amount":"","unit":"","isSection":true},{"name":"bawang merah besar","amount":"3","unit":"biji","isSection":false},{"name":"cili kering – rebus/rendam dulu, buang biji (ikut citarasas)","amount":"10-20","unit":"tangkai","isSection":false},{"name":"air untuk kisar","amount":"Sedikit","unit":"","isSection":false},{"name":"Bahan lain","amount":"","unit":"","isSection":true},{"name":"sotong – bersihkan","amount":"1","unit":"kg","isSection":false},{"name":"minyak masak (menumis)","amount":"½","unit":"cawan","isSection":false},{"name":"air asam jawa (ikut citarasa)","amount":"1-2","unit":"sudu besar","isSection":false},{"name":"gula melaka/gula perang (ikut citarasa)","amount":"1","unit":"sudu besar","isSection":false},{"name":"kicap manis","amount":"1","unit":"sudu besar","isSection":false},{"name":"Garam","amount":"secukup rasa","unit":"","isSection":false},{"name":"bawang besar (hiris untuk menumis)","amount":"1","unit":"biji","isSection":false},{"name":"bawang besar (potong wedges untuk finishing)","amount":"1","unit":"biji","isSection":false},{"name":"santan (ikut citarasa)","amount":"5","unit":"sudu besar","isSection":false},{"name":"Air","amount":"secukupnya","unit":"","isSection":false}]'::jsonb,
  '["Kisar semua bahan sehingga halus. Ketepikan seketika.","Bersihkan sotong. Potong ikut citarasa.","Dalam kuali masukkan sotong. Biarkan sotong masak seketika sehingga","air sotong keluar. Anggaran 2-3minit.  Toskan sotong. Air sotong boleh di","simpan untuk masukkan semasa memasak sambal. Step ini di buat","untuk memastikan sotong tidak over cooked.","Dalam kuali yang sama, panaskan minyak. Tumiskan bawang besar yang","telah di hiris sehingga naik bau.","Kemudian, masukkan semua bahan kisar. Tumis sehingga naik bau dan","mula pecah minyak. Bila sambal dah garing dan pecah minyak, warna","sambal akan bertukar warna gelap sedikit. Sepanjang proses ini boleh","tambah air sedikit sebanyak 2 kali. Hal ini untuk memastikan sambal","masak sempurna dan sambal akan pecah minyak dengan cantik.","Seterusnya, boleh masukkan air sotong tadi, air asam jawa, gula, kicap","manis dan garam. Gaul rata semua bahan dan suaikan dengan citarasa.","Tambah sedikit air jika kuah sambal terlalu kering.","Kemudian masukkan santan. Biarkan semua bahan mesra seketika.","Reneh perlahan.","Sambung masak sehingga sambal nampak semakin garing. Masukkan","sotong. Rasa dan suaikan dengan citarasa.","Gaulkan sehingga semua bahan sebati.","Kemudian masukkan bawang besar yang di wadges. Kacau sehingga","sebati. Renehkan anggaran 1minit. Kemudian boleh tutup api. Sedia","untuk di hidang."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- LABU MASAK LEMAK SEMPOI
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'LABU MASAK LEMAK SEMPOI',
  'labu-masak-lemak-sempoi',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/labu-masak-lemak-sempoi.jpeg',
  NULL,
  '[{"name":"bawang besar (tumbuk)","amount":"1","unit":"biji","isSection":false},{"name":"bawang putih (tumbuk)","amount":"3","unit":"ulas","isSection":false},{"name":"lada hitam (Jika suka)","amount":"½","unit":"sudu kecil","isSection":false},{"name":"serai (diketuk)","amount":"1","unit":"Batang","isSection":false},{"name":"ikan bilis/udang kering (rendam, tumbuk)","amount":"Segenggam","unit":"","isSection":false},{"name":"daun kunyit (hiris)","amount":"1-2","unit":"helai","isSection":false},{"name":"labu kuning (potong kiub sederhana)","amount":"½","unit":"biji","isSection":false},{"name":"kotak santan (kecil)","amount":"1","unit":"","isSection":false},{"name":"air (atau secukupnya)","amount":"1","unit":"cawan","isSection":false},{"name":"Garam","amount":"secukup rasa","unit":"","isSection":false}]'::jsonb,
  '["Masukkan air, didihkan seketika. Kemudian masukkan bawang besar, bawang putih dan ikan bilis atau udang kering yang telah di tumbuk. Masukkan lada hitam jika suka.","Biarkan hingga naik bau seketika.","Tambah labu. Rebus hingga labu lembut (lebih kurang 5-8 minit).","Bila Labu dah empuk, perlahankan api.","Tuang santan, kacau perlahan supaya tak pecah minyak.","Bila kuah mula mendidih, masukkan daun kunyit. Gaul sebentar hingga layu. Tak perlu lama.","Tambah garam secukup rasa. Kacau sekejap dan tutup api."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- CRUNCHY CAULIFLOWER CWC
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'CRUNCHY CAULIFLOWER CWC',
  'crunchy-cauliflower-cwc',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/crunchy-cauliflower-cwc.jpeg',
  NULL,
  '[{"name":"kuntum cauliflower, direbus","amount":"1","unit":"","isSection":false},{"name":"tepung gandum","amount":"1","unit":"cawan","isSection":false},{"name":"tepung jagung","amount":"1","unit":"sudu besar","isSection":false},{"name":"paprika","amount":"1","unit":"sudu kecil","isSection":false},{"name":"serbuk bawang putih","amount":"1","unit":"sudu kecil","isSection":false},{"name":"serbuk cumin","amount":"1","unit":"sudu kecil","isSection":false},{"name":"Garam & lada hitam","amount":"secukup rasa","unit":"","isSection":false},{"name":"telur","amount":"2","unit":"biji","isSection":false},{"name":"/2 cawan air","amount":"1","unit":"","isSection":false},{"name":"Minyak, untuk menggoreng","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Didihkan air secukupnya untuk merebus cauliflower.","Potong cauliflower, rebus hingga lembut (jangan terlalu lembik). Anggaran 3-4minit. Toskan.","Dalam mangkuk, campurkan tepung, cornstarch, paprika, garlic powder, cumin, garam & lada hitam. Gaul sehingga sebati.","Kemudian masukkan telur dengan air. Kacau sehingga semua bahan sebati.","Panaskan minyak untuk menggoreng secukupnya.","Celup cauliflower ke dalam bancuhan tepung.","Goreng dalam minyak panas hingga keemasan & rangup. Lepas rehat 1-2 minit boleh buat double fry.","Toskan dan hidang dengan sos pilihan."]'::jsonb,
  '["NOTA: OPTIONAL TANPA TELUR\nKalau nak buat tanpa telur, ganti langkah telur (Step 4):\nPilihan pengganti telur (pilih salah satu):\n1. Batter tepung + air\n* 1 cup flour\n* 1 tbsp cornstarch\n* 1/2 tsp baking powder (optional untuk extra rangup)\n* Air secukupnya → jadikan batter pekat\n2. Buttermilk vegan\n* 1/2 cup susu (atau air)\n* 1–2 tbsp lemon juice / cuka"]',
  '["Main"]'::jsonb,
  false
);

-- SPECIAL RANCH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SPECIAL RANCH',
  'special-ranch',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/special-ranch.jpeg',
  NULL,
  '[{"name":"/2 cawan mayonis","amount":"1","unit":"","isSection":false},{"name":"/2 cawan sour cream atau Greek yogurt","amount":"1","unit":"","isSection":false},{"name":"susu atau buttermilk (ubah mengikut kepekatan yang diingini)","amount":"2-3","unit":"sudu besar","isSection":false},{"name":"serbuk bawang putih","amount":"1","unit":"sudu kecil","isSection":false},{"name":"serbuk bawang","amount":"1","unit":"sudu kecil","isSection":false},{"name":"dill kering","amount":"1","unit":"sudu kecil","isSection":false},{"name":"/2 sudu kecil parsley kering","amount":"1","unit":"","isSection":false},{"name":"/2 sudu kecil chives kering (pilihan, tetapi sedap)","amount":"1","unit":"","isSection":false},{"name":"/4 sudu kecil lada hitam","amount":"1","unit":"","isSection":false},{"name":"/4-1/2 sudu kecil garam (ikut rasa)","amount":"1","unit":"","isSection":false},{"name":"jus lemon atau cuka (untuk rasa masam)","amount":"1-2","unit":"sudu kecil","isSection":false}]'::jsonb,
  '["Campurkan mayo + sour cream/Greek yogurt dalam mangkuk.","Masukkan garlic powder, onion powder, dill, parsley, chives, garam & lada hitam.","Tambah lemon juice.","Tambah susu / buttermilk sedikit-sedikit sampai dapat kepekatan yang suka (lebih cair untuk dressing, lebih pekat untuk dip).","Gaul sebati dan simpan dalam peti 30 minit sebelum hidang (lagi sedap bila dah “marinate”)."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- BROWNIE PUDDING
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'BROWNIE PUDDING',
  'brownie-pudding',
  'Dessert',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/brownie-pudding.jpeg',
  NULL,
  '[{"name":"mentega tanpa garam, ditambah sedikit untuk bekas","amount":"226","unit":"gm","isSection":false},{"name":"telur (Gred A- suhu bilik)","amount":"4","unit":"biji","isSection":false},{"name":"gula (330-400gm) -ikut citarasa","amount":"2","unit":"cawan","isSection":false},{"name":"/4 cawan serbuk koko berkualiti (65gm)","amount":"3","unit":"","isSection":false},{"name":"/2 cawan tepung gandum (AP flour)","amount":"1","unit":"","isSection":false},{"name":"esen vanila","amount":"1","unit":"sudu teh","isSection":false},{"name":"Aiskrim vanilla, untuk dihidang (Jika ada)","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Panaskan ketuhar pada 160°C (325°F).","Sapu mentega pada bekas 2-quart (lebih kurang 23 x 30 x 5 cm). Cairkan mentega dan biarkan sejuk.","Dalam mixer (paddle), pukul telur dan gula pada kelajuan sederhana-tinggi selama 5-10 minit sehingga pekat & pucat.","Ayak koko dan tepung. Ketepikan.","Rendahkan kelajuan mixer dan masukkan Esen vanila dan campuran koko dan tepung. Pukul sekejap sahaja sehingga sebati.","Kekalkan mixer kelajuan rendah dan tuang perlahan-lahan mentega cair. Pukul sekadar cukup sebati.","Tuang adunan ke dalam bekas baking. Letakkan bekas itu ke dalam loyang yang lebih besar.","Tuang air panas ke dalam loyang besar sehingga paras setengah tinggi bekas adunan (water bath).","Bakar tepat 1 jam. Bila cucuk 2 inci dari tepi, tester akan keluar 3/4 bersih.","Bahagian tengah akan masih lembik, memang begitu. Hidang panas dengan aiskrim vanila."]'::jsonb,
  '["Nota tambahan:\n1. Saiz bekas / loyang\n• Panjang: 9 inci\n• Lebar: 12 inci\n• Tinggi: 2 inci\n2. Alternatif lain jika tiada:\n• Loyang bulat: 9–10 inci diameter, tinggi 2 inci\n• Loyang segiempat / kotak: 9 × 12 inci, tinggi 2 inci\n3. Pastikan loyang cukup dalam untuk water bath, supaya bahagian tengah tidak cepat kering."]',
  '["Dessert"]'::jsonb,
  false
);

