  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/yee-mee-goreng-mudah.jpeg',
  NULL,
  '[{"name":"yee mee","amount":"4","unit":"keping","isSection":false},{"name":"bawang putih (Ketuk)","amount":"3","unit":"ulas","isSection":false},{"name":"isi ayam, hiris nipis","amount":"1","unit":"keping","isSection":false},{"name":"kobis panjang, hiris kasar","amount":"Sedikit","unit":"","isSection":false},{"name":"pokok pak choy, potong ikut citarasa","amount":"5","unit":"","isSection":false},{"name":"cendawan shiitake kering (rendam- hiris)","amount":"6","unit":"keping","isSection":false},{"name":"minyak masak","amount":"4","unit":"sudu besar","isSection":false},{"name":"Air","amount":"secukupnya","unit":"","isSection":false},{"name":"Bahan Sos (Campur semua bahan di bawah)","amount":"","unit":"","isSection":false},{"name":"kicap cair","amount":"2","unit":"sudu besar","isSection":false},{"name":"kicap biasa","amount":"2","unit":"sudu besar","isSection":false},{"name":"sos tiram","amount":"1","unit":"sudu besar","isSection":false},{"name":"sos cili","amount":"2","unit":"sudu besar","isSection":false},{"name":"perasa","amount":"2","unit":"sudu teh","isSection":false},{"name":"gula perang","amount":"2","unit":"sudu teh","isSection":false},{"name":"gula perang","amount":"2","unit":"sudu teh","isSection":false}]'::jsonb,
  '["Cuci bersih kemudian rendam cendawan shiitake dalam air biasa 1 jam hingga lembut. Tos dan hiris jika besar, simpan air rendaman cendawan.","Rendam yee mee sekejap dalam air suam 2-3 minit hingga mi lembut tapi jangan terlalu lembik. Tos air. Kalau tak nak rendam pun boleh.","Panaskan 2 sudu besar minyak dalam kuali/wok. Tumis bawang putih sehingga naik bau. Masukkan ayam tumis hingga separuh masak.","Masukkan cendawan shiitake dan kacau sebati.","Tuang sos yang telah dicampur ke atas ayam dan cendawan.","Masukkan sedikit air rendaman cendawan untuk menambah aroma dan kuah pekat, kacau sebati. Biarkan reneh seketika. Jika tak rendam Yee Mee, boleh masukkan sekarang. Kemudian tutup sekejap kuali. Biarkan yee mee sedikit lembut. Tambah air panas jika perlu.","Pecahkan telur ke dalam kuali, Biarkan set seketika, kemudian kacau rata.","Masukkan kobis dan pak choy, kacau sekejap hingga layu tapi masih rangup.","Jika rendam yee mee awal, boleh masukkan yee mee sekarang. Gaul rata supaya semua bahan sebati dan mi terbalut sos dengan baik.","Angkat dan hidangkan panas-panas."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- EASY SHAKSHUKA
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'EASY SHAKSHUKA',
  'easy-shakshuka',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/easy-shakshuka.jpeg',
  NULL,
  '[{"name":"telur","amount":"4-6","unit":"biji","isSection":false},{"name":"minyak zaitun (45 ml)","amount":"3","unit":"sudu besar","isSection":false},{"name":"bawang besar, dadu (180 g)","amount":"1","unit":"biji","isSection":false},{"name":"lada benggala merah, dadu","amount":"1","unit":"biji","isSection":false},{"name":"bawang putih, parut/hancur","amount":"4","unit":"ulas","isSection":false},{"name":"serbuk paprika","amount":"1","unit":"sudu besar","isSection":false},{"name":"serbuk jintan putih (cumin)","amount":"2","unit":"sudu kecil","isSection":false},{"name":"serbuk cili","amount":"1","unit":"sudu kecil","isSection":false},{"name":"garam (secukupnya)","amount":"½ -1","unit":"sudu kecil","isSection":false},{"name":"lada hitam (secukupnya)","amount":"½ -1","unit":"sudu kecil","isSection":false},{"name":"tomato (whole peeled/dice tomatoes) 28 oz / 800 g","amount":"2","unit":"tin","isSection":false},{"name":"daun parsley atau daun ketumbar, dicincang","amount":"¼","unit":"cawan","isSection":false},{"name":"Lebihan daun parsley/ketumbar untuk hiasan","amount":"","unit":"","isSection":false},{"name":"Cheese Pilihan","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Dalam skillet 10 inch / kuali besi, panaskan minyak atas api sederhana.","Masukkan bawang dan capsicum. Masak 10-15 minit sampai lembut & sedikit perang.","Masukkan bawang putih, serbuk paprika, cumin, chili powder, garam & lada hitam. Gaul 2 minit sampai wangi.","Kemudian, masukkan peeled tomato. Hancurkan tomato dengan sudip kayu.","Didihkan sekejap, kemudian kecilkan api.","Reneh 20 minit sampai pekat & sedikit reduce. Masukkan parsley/cilantro.","Guna belakang sudu besar, buat 6 lubang kecil dalam sos. Pecahkan 1 telur dalam setiap lubang.","Tutup kuali dan masak 5-10minit. Masa bergantung jenis dapur yang anda guna. Jadi pastikan sampai putih telur set, kuning masih runny.","Tabur Cheese dan parsley/cilantro, hidang panas-panas dengan roti crusty, sourdough atau pita."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- CREAMY LEMONADE
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'CREAMY LEMONADE',
  'creamy-lemonade',
  'Dessert',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/creamy-lemonade.jpeg',
  NULL,
  '[{"name":"limau nipis (fresh green lemons)","amount":"5","unit":"biji","isSection":false},{"name":"Ais kiub","amount":"secukupnya","unit":"","isSection":false},{"name":"garam","amount":"Secubit","unit":"","isSection":false},{"name":"gula","amount":"3","unit":"sudu besar","isSection":false},{"name":"susu pekat manis (ikut citarasa)","amount":"1","unit":"cawan","isSection":false},{"name":"air sejuk","amount":"2","unit":"cawan","isSection":false}]'::jsonb,
  '["A. Sediakan Jus Limau","Belah semua limau dan perah menggunakan hand juicer.","Buang biji supaya jus tak pahit.","Kumpulkan jus dalam mangkuk dan ketepikan.","B. Blend Lemonade","Dalam blender, masukkan beberapa ketul ais.","Tambah jus limau yang diperah tadi.","Masukkan secubit garam, 3 sudu besar gula dan 1 cawan susu pekat manis.","Susu pekat boleh adjust ikut citarasa.","Tuang 2 cawan air sejuk.","Tutup penutup blender dan kisar sampai halus, sebati dan creamy.","C. Hidang","Sediakan gelas tinggi dan penuhkan dengan ais.","Tuang lemonade yang telah siap diblend.","Hias dengan hirisan limau di atas.","Hidang sejuk-sejuk — memang segar."]'::jsonb,
  NULL,
  '["Dessert"]'::jsonb,
  false
);

-- EASY CORDON BLEU
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'EASY CORDON BLEU',
  'easy-cordon-bleu',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/easy-cordon-bleu.jpeg',
  NULL,
  '[{"name":"/3 cawan breadcrumbs (35g)","amount":"2","unit":"","isSection":false},{"name":"butter cair","amount":"1","unit":"sudu besar","isSection":false},{"name":"/4 sudu kecil garam","amount":"1","unit":"","isSection":false},{"name":"/4 sudu kecil lada hitam","amount":"1","unit":"","isSection":false},{"name":"dada ayam tanpa tulang & kulit","amount":"2","unit":"keping","isSection":false},{"name":"keju pilihan (Jenis slice)","amount":"4","unit":"keping","isSection":false},{"name":"hirisan turkey slices/smoke beef (4 keping)","amount":"113","unit":"g","isSection":false},{"name":"tepung gandum (20g)","amount":"3½","unit":"sudu besar","isSection":false},{"name":"telur (dipukul)","amount":"1","unit":"biji","isSection":false}]'::jsonb,
  '["Panaskan oven pada suhu 375°F (190°C). Sediakan wire rack di atas loyang berbingkai. Set api atas bawah dan off kipas jika boleh.","Dalam bekas campurkan Breadcrumbs, butter cair, garam, dan lada hitam. Ketepikan.","Sediakan ayam. Belah butterfly setiap dada ayam, tetapi jangan sampai terputus sepenuhnya.","Buka ayam seperti buku, letak plastik wrap di atasnya dan pukul hingga setebal ¼ inci (lebih kurang 0.6 cm).","── 4. Dengan bahagian dalam ayam menghadap ke atas ──","* Letakkan lapisan keju yang jenis slice","* Susun hirisan turkey slices/smoke beef di atas keju.","* Gulung ayam ketat seperti swiss roll.","* Semat bahagian sambungan dengan toothpick.","── 5. Salutan ayam ──","° Masukkan tepung dalam satu bekas.","° Telur dipukul dalam satu bekas lain.","° Salut ayam dalam tepung, kemudian telur, kemudian bread crumb sehingga rata.","Susun gulungan ayam di atas wire rack. Letakkan ayam di rak tengah dalam oven.","Bakar selama 35-45 minit atau sehingga Warna keemasan.","Dah siap bakar, rehatkan seketika anggaran 5-10minit. Kemudian boleh hidangkan bersama sos pilihan dan salad."]'::jsonb,
  NULL,
  '["Main","Ayam"]'::jsonb,
  false
);

-- CREAM SAUCE (CORDON BLEU)
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'CREAM SAUCE (CORDON BLEU)',
  'cream-sauce-cordon-bleu',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/cream-sauce-cordon-bleu.jpeg',
  NULL,
  '[{"name":"butter tanpa garam","amount":"2","unit":"sudu besar","isSection":false},{"name":"tepung gandum","amount":"2","unit":"sudu besar","isSection":false},{"name":"susu (240 ml)","amount":"1","unit":"cawan","isSection":false},{"name":"Dijon/yellow mustard","amount":"2","unit":"sudu besar","isSection":false},{"name":"keju Parmesan parut (20 g)","amount":"¼","unit":"cawan","isSection":false}]'::jsonb,
  '["Cairkan butter dalam periuk kecil di atas api sederhana.","Bila butter berbuih, masukkan tepung dan kacau dengan whisk selama 2 minit.","Perlahan-lahan tuang susu sambil terus dikacau hingga sebati.","Masukkan mustard dan kacau hingga rata.","Kecilkan api ke sederhana-rendah dan kacau sehingga sos memekat (5–7 minit).","Tutup api dan masukkan keju Parmesan sedikit demi sedikit, kacau hingga larut sepenuhnya.","Hidang segera di atas Chicken Cordon Bleu."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);

-- EXPRESS SALAD
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video_url, ingredients, steps, notes, tags, is_featured)
VALUES (
  'EXPRESS SALAD',
  'express-salad',
  'Main',
  'VOL 15',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-15/express-salad.jpeg',
  NULL,
  '[{"name":"Bahan Salad","amount":"","unit":"","isSection":true},{"name":"kepala lettuce segar (dicuci dan dipotong saiz sederhana)","amount":"1","unit":"","isSection":false},{"name":"/2 biji timun (dipotong bulat atau dadu, optional)","amount":"1","unit":"","isSection":false},{"name":"tomato ceri (dibelah dua, optional)","amount":"6-8","unit":"biji","isSection":false},{"name":"/4 biji bawang merah (dihiris nipis, optional)","amount":"1","unit":"","isSection":false},{"name":"kacang badam panggang / walnut (optional, untuk rasa rangup)","amount":"2","unit":"sudu besar","isSection":false},{"name":"Bahan Dressing","amount":"","unit":"","isSection":true},{"name":"/8 cawan (2 sudu makan) minyak zaitun extra virgin","amount":"1","unit":"","isSection":false},{"name":"/2 sudu teh garam laut","amount":"1","unit":"","isSection":false},{"name":"/2 sudu teh lada hitam","amount":"1","unit":"","isSection":false},{"name":"Jus 1/2 lemon segar","amount":"","unit":"","isSection":false},{"name":"maple syrup /madu","amount":"1","unit":"sudu teh","isSection":false}]'::jsonb,
  '["Sediakan sayur: Cuci lettuce hingga bersih dan tos sehingga kering. Potong saiz sederhana. Jika guna timun, tomato ceri atau bawang merah, sediakan juga.","Buat dressing: Dalam mangkuk kecil, campurkan minyak zaitun, garam, lada, jus lemon dan maple syrup. Kacau sehingga sebati.","Gaul salad: Masukkan semua sayur dalam mangkuk besar. Tuangkan dressing. Gaul rata supaya semua sayur bersalut dressing.","Hiaskan & hidang: Taburkan kacang panggang di atas (jika guna). Hidangkan segera supaya lettuce tetap rangup."]'::jsonb,
  NULL,
  '["Main"]'::jsonb,
  false
);
